/**
 * Team chat — uses shared API client.
 */
import { createTeamChatService } from '@cagupta/shared-services';
import { apiClient } from '../../../adapters/apiClient';

const chat = createTeamChatService(apiClient);

export async function fetchConversations() {
  return chat.fetchConversations();
}

export async function fetchConversation(id) {
  return chat.fetchConversation(id);
}

export async function createConversation(payload) {
  return chat.createConversation(payload);
}

export async function fetchMessages(conversationId, { afterId = 0, beforeId = 0, limit = 50 } = {}) {
  return chat.fetchMessages(conversationId, { afterId, beforeId, limit });
}

export async function sendMessage(conversationId, bodyText) {
  return chat.sendMessage(conversationId, bodyText);
}

export async function markConversationRead(conversationId, messageId) {
  return chat.markConversationRead(conversationId, messageId);
}

export async function fetchChatContacts() {
  return chat.fetchContacts();
}

export async function fetchChatUnreadCount() {
  const data = await apiClient.get('/chat/unread-count');
  return data.data?.unread_count ?? 0;
}

export async function addChannelMembers(conversationId, userIds) {
  const data = await apiClient.post(`/chat/conversations/${conversationId}/members`, { user_ids: userIds });
  return data.data;
}

export async function leaveChannel(conversationId) {
  return chat.leaveChannel(conversationId);
}

export async function searchChatAudit({
  q = '', senderUserId = 0, conversationId = 0, dateFrom = '', dateTo = '',
  conversationType = '', senderKind = '', page = 1, perPage = 50,
} = {}) {
  const data = await apiClient.get('/admin/chat/audit', {
    page,
    per_page: perPage,
    q: q || undefined,
    sender_user_id: senderUserId > 0 ? senderUserId : undefined,
    conversation_id: conversationId > 0 ? conversationId : undefined,
    date_from: dateFrom || undefined,
    date_to: dateTo || undefined,
    conversation_type: conversationType || undefined,
    sender_kind: senderKind || undefined,
  });
  return { rows: data.data || [], pagination: data.pagination || {} };
}

export async function fetchAuditConversationThread(conversationId, { limit = 100 } = {}) {
  const data = await apiClient.get(`/admin/chat/audit/conversations/${conversationId}`, { limit });
  return data.data;
}
